code = """import json

# Get data from storage
civic_docs_file = var_functions.query_db:26
funding_records = var_functions.query_db:48

# Load civic documents
try:
    with open(civic_docs_file, 'r') as f:
        civic_docs = json.load(f)
except Exception as e:
    print(f'Error loading civic docs: {e}')
    civic_docs = []

# Build status map
status_map = {}
for doc in civic_docs:
    text = doc.get('text', '')
    if not text:
        continue
    lines = text.split('\n')
    current_section = None
    
    for line in lines:
        line = line.strip()
        if not line:
            continue
        
        # Detect sections
        if 'Design' in line and ('Capital' in line or 'Disaster' in line):
            current_section = 'design'
        elif 'Construction' in line and ('Capital' in line or 'Disaster' in line):
            current_section = 'construction'
        elif 'Not Started' in line and ('Capital' in line or 'Disaster' in line):
            current_section = 'not_started'
        
        # Add project to status map
        if current_section and len(line) > 10 and not line.startswith('(') and 'Updates' not in line and 'Schedule' not in line and 'Page' not in line and 'Project Description' not in line:
            base = line.split('(')[0].strip()
            if base:
                status_map[base] = 'completed' if current_section == 'construction' else current_section

print('Status map entries:', len(status_map))

# Find project statuses
final_data = []
for rec in funding_records:
    pname = rec['Project_Name']
    base = pname.split('(')[0].strip()
    status_val = 'unknown'
    
    if base in status_map:
        status_val = status_map[base]
    else:
        # Fuzzy match
        for key in status_map:
            if base.lower() in key.lower():
                status_val = status_map[key]
                break
    
    final_data.append([
        pname,
        rec['Funding_Source'],
        int(rec['Amount']),
        status_val
    ])

# Sort by project name
final_data.sort(key=lambda x: x[0])

# Build output
output = []
for item in final_data:
    output.append('Project: ' + item[0])
    output.append('Funding Source: ' + item[1])
    output.append('Amount: $' + '{:,}'.format(item[2]))
    output.append('Status: ' + item[3])
    output.append('-' * 70)

result = {
    'count': len(final_data),
    'total_funding': sum(item[2] for item in final_data),
    'output': '\n'.join(output)
}

print('__RESULT__:')
print(json.dumps(result))"""

